import{_ as a,o as t,c as p,j as r,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const N=JSON.parse('{"title":"N公司 大锤套装","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/6.套装/N公司 大锤套装.md","filePath":"4.资源分区/7.物品与装备/6.套装/N公司 大锤套装.md"}'),o={name:"4.资源分区/7.物品与装备/6.套装/N公司 大锤套装.md"};function d(_,e,b,l,i,c){return t(),p("div",null,[...e[0]||(e[0]=[r("h1",{id:"n公司-大锤套装",tabindex:"-1"},[n("N公司 大锤套装 "),r("a",{class:"header-anchor",href:"#n公司-大锤套装","aria-label":'Permalink to "N公司 大锤套装"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘")])])],-1),s('<h1 id="n公司-大锤套装-1" tabindex="-1">N公司-大锤套装 <a class="header-anchor" href="#n公司-大锤套装-1" aria-label="Permalink to &quot;N公司-大锤套装&quot;">​</a></h1><p>N公司-大锤套装<br> N公司内部存在钉子派与锤子派，而大部分的N公司异端审判官都一手执钉，一手执锤，并穿有沉重的金属盔甲，并由红色绸缎装饰。</p><p>N公司“大锤”狂信者盔甲<br> B+2000<br> 盔甲类型：重甲<br> 盔甲减值：8<br> 盔甲防御：25/25<br> 特性：愚不可及…<br> 当穿戴此盔甲，并试图进行招架时，不再进行招架，而是立刻获得2层守护，并进入反击状态。如果此时穿戴者已不具有任何完好，则【反击状态】额外增加6点固定伤害。</p><p>【守护】：具有守护时，即使生命中的最好状态不存在任何完好，也不会昏迷，伤势也不会自动恶化。每具有1层守护，就获得等同于人物内在支线等级数*1的物理伤害减免（D1C2…S5），同一特性或技艺提供的守护不能叠加。守护状态持续一轮。</p><p>反击状态：处于反击状态时，招架将不再提供对于某次攻击的伤害抵销，而是在招架结算时，改为对攻击者造成等同于应得伤害抵销数目的固定伤害，这些伤害不能被豁免，但可以被伤害吸收等方式吸收，与招架相同，进行过一次反击后会立刻结束反击状态。</p><p>尖钉与大锤<br> B+2000<br> 尖钉与大锤是一对武器，必须一手执其中之一，并一同使用才具有武器伤害和武器特性。<br> 尖钉的武器伤害为17L，具有【轻灵】与高速8。大锤的武器伤害为19L，具有威猛8。<br> 在购买尖钉与大锤时，还会额外获得下列三项技艺，均需要用钉与锤才能施展。</p><p>穿刺钉刑：使用尖钉，以一个标准动作对攻击范围内的一个目标进行一次攻击，这是一个攻击技。本次攻击可以应用大锤上的武器特性，且尖钉额外获得2点破甲。若成功造成伤害，则给予自身1层守护。</p><p>涤净汝罪：使用大锤，以一个标准动作对攻击范围内的一个目标进行一次攻击，这是一个攻击技。本次攻击可以应用尖钉上的武器特性，且大锤额外获得2点威猛。若成功造成伤害，则对目标施加3层尖钉，若该目标具有的尖钉不少于5层，则再降低其6点先攻，持续一个场景。</p><p>异端抹杀：使用大锤，以一个标准动作对攻击范围内的一个目标进行一次攻击，这是一个攻击技。本次攻击可以同时应用尖钉和大锤上的武器特性。若成功造成伤害，则给予自身1层狂信，被攻击者需再以一个强韧豁免对抗这次攻击的出目，若对抗失败，则视为陷入B级创伤来源的胁迫状态之中，只能优先选择你为攻击目标，持续一轮。若此时你已不具有任何完好，则获得1层守护，并获得2点仅能使用一次的快速医疗（医疗点24）。</p><p>【尖钉】：具有尖钉的目标视为具有等同于尖钉层数的不可豁免的流血点数，这些流血点数只有在携带者进行攻击检定时才会立刻生效，每轮至多生效一次。</p><p>【狂信】：若被攻击的目标具有尖钉，则对其造成的伤害中会有至多等同于狂信层数点严重伤害转化为韧性伤害，同一特性或技艺提供的狂信不能叠加。狂信状态持续一轮。</p><p>套装效果：穿戴大锤套装后，穿戴者获得守护层数时提升1层守护层数；穿戴者获得狂信状态时，提升1层狂信状态。<br> 以上二种效果每轮只会各自生效一次。</p><p>专属专长<br> 仅当你穿着大锤套装可以购买并使用以下专长</p><p>执念之锤（3）<br> 本专长在你不具有任何完好时触发。<br> 每轮开始时获得1层守护与1点仅能使用一次的异常点数治疗（医疗点24），再给予自身1层狂信。</p><p>无上荣光（2）<br> 在战斗中每轮一次，若有生命状态比你更差的一名友方单位，且你与其的状态均不具有任何完好，则为其提供1层守护和1层狂信。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',17)])])}const f=a(o,[["render",d]]);export{N as __pageData,f as default};
